create table if not exists clients (id uuid primary key default gen_random_uuid(), name text, phone text, address text, source text default 'Сайт', status text default 'Новая заявка', measure_date date, comment text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists calculations (id uuid primary key default gen_random_uuid(), client_id uuid references clients(id) on delete cascade, prices jsonb, items jsonb, totals jsonb, materials jsonb, created_at timestamptz default now());
create table if not exists client_history (id uuid primary key default gen_random_uuid(), client_id uuid references clients(id) on delete cascade, type text, text text, amount numeric default 0, extra jsonb, created_at timestamptz default now());
alter table clients enable row level security; alter table calculations enable row level security; alter table client_history enable row level security;
drop policy if exists "public read clients" on clients; drop policy if exists "public insert clients" on clients; drop policy if exists "public update clients" on clients; drop policy if exists "public delete clients" on clients;
drop policy if exists "public read calculations" on calculations; drop policy if exists "public insert calculations" on calculations; drop policy if exists "public update calculations" on calculations; drop policy if exists "public delete calculations" on calculations;
drop policy if exists "public read history" on client_history; drop policy if exists "public insert history" on client_history; drop policy if exists "public update history" on client_history; drop policy if exists "public delete history" on client_history;
create policy "public read clients" on clients for select using (true); create policy "public insert clients" on clients for insert with check (true); create policy "public update clients" on clients for update using (true) with check (true); create policy "public delete clients" on clients for delete using (true);
create policy "public read calculations" on calculations for select using (true); create policy "public insert calculations" on calculations for insert with check (true); create policy "public update calculations" on calculations for update using (true) with check (true); create policy "public delete calculations" on calculations for delete using (true);
create policy "public read history" on client_history for select using (true); create policy "public insert history" on client_history for insert with check (true); create policy "public update history" on client_history for update using (true) with check (true); create policy "public delete history" on client_history for delete using (true);
